const agentName = msg.payload.agent_name || msg.payload.agent_id || 'unknown';
const errorText = msg.payload.response_text || 'No response';
const model = msg.payload.model || 'unknown';
const duration = msg.payload.duration_ms || 0;

msg.payload = `Agent '${agentName}' failed after ${duration}ms using model '${model}'. ` +
  `Error response: ${errorText}. ` +
  `Diagnose the likely cause and suggest a fix.`;

return msg;
